#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N; scanf("%d",&N);
        int nums[30000]; // maximum possible size
        for(int i=0;i<N;i++) scanf("%d",&nums[i]);
        if(N==0){
            printf("0\n\n");
            continue;
        }
        int k=0; // index of last unique element
        for(int i=1;i<N;i++){
            if(nums[i]!=nums[k]){
                k++;
                nums[k]=nums[i];
            }
        }
        int K=k+1;
        printf("%d\n",K);
        for(int i=0;i<K;i++) printf("%d ",nums[i]);
        printf("\n");
    }
    return 0;
}

